INSERT INTO public.fci_fondo (id, nombre, categoria_id, gestora_id, depositaria_id, clasificacion, region, horizonte, benchmark, moneda_id, inicio, estado, codigo_cnv, objetivo, dias_liquidacion) VALUES
  (1520, 'Max Renta Fija Latam', 3, 3014, 115, 'Renta Fija', 'Argentina', 'Mediano Plazo', NULL, 2, '2024-07-04', 1, '1391', 'El objetivo del fondo es preservar el valor del patrimonio del fondo y obtener ganancias derivadas de la compra y venta de valores negociables, instrumentos financieros y otros activos financieros emitidos y negociados en la República Argentina.', 2),
  (1666, 'Max Retorno Total Pesos', 7, 3014, 115, 'Renta Fija', 'Argentina', 'Flexible', NULL, 1, '2025-07-02', 1, '1702', 'El objetivo del fondo seré el de maximizar el retorno en pesos, a través de una gestión activa, invirtiendo en instrumentos de renta fija y/o variable.', 1),
  (1727, 'Max Retorno Total Pesos II', 7, 3014, 115, 'Renta Fija', 'Argentina', 'Flexible', NULL, 1, '2025-09-22', 1, '1753', 'El objetivo del fondo seré el de maximizar el retorno en pesos, a través de una gestión activa, invirtiendo en instrumentos de renta fija y/o variable.', 1),
  (1728, 'Max Retorno Total Pesos III', 7, 3014, 115, 'Renta Fija', 'Argentina', 'Flexible', NULL, 1, '2025-09-22', 1, '1754', 'El objetivo del fondo seré el de maximizar el retorno en pesos, a través de una gestión activa, invirtiendo en instrumentos de renta fija y/o variable.', 1),
  (1729, 'Max Retorno Total Pesos IV', 7, 3014, 115, 'Renta Fija', 'Argentina', 'Flexible', NULL, 1, '2025-09-22', 1, '1755', 'El objetivo del fondo seré el de maximizar el retorno en pesos, a través de una gestión activa, invirtiendo en instrumentos de renta fija y/o variable.', 1),
  (611, 'Megainver Renta Global', 3, 378, 115, 'Renta Fija', 'Argentina', 'Largo Plazo', NULL, 1, '2015-05-06', 1, '760', 'El fondo tiene como objetivo lograr una rentabilidad ajustada por riesgo, superior a un conjunto de instrumentos de renta fija de corto/mediano plazo mediante una adecuada diversificación de sus activos. El horizonte de inversión del fondo es de corto/mediano plazo.', 1),
  (378, 'MEGAQM Acciones', 2, 378, 387, 'Renta Variable', 'Argentina', 'Largo Plazo', NULL, 1, '2017-09-05', 1, '755', 'Obtener una apreciación de capital en el largo plazo, invirtiendo en una cartera diversificada de acciones de empresas argentinas que cotizan en la bolsa de Comercio de Buenos Aires.', 1),
  (656, 'MEGAQM Acciones Latam', 5, 378, 115, 'Renta Mixta', 'Argentina', 'Mediano Plazo', NULL, 1, '2017-09-05', 1, '805', 'El fondo tiene como objetivo lograr una rentabilidad ajustada por riesgo, superior a un conjunto de instrumentos de renta fija de mediano plazo mediante una adecuada diversificación de sus activos. El horizonte de inversión del fondo es de mediano plazo. Este fondo puede distribuir utilidades de acuerdo al procedimiento de distribución de utilidades aprobado por CNV y serán oportunamente informadas mediante un "Hecho Relevante" en AIF.', 1),
  (404, 'MEGAQM Ahorro', 3, 378, 387, 'Renta Fija', 'Argentina', 'Corto Plazo', NULL, 1, '2006-08-14', 1, '515', 'Obtener retornos superiores  a un plazo fijo tradicional, con muy bajo riesgo y sin tener que inmovilizar el dinero por un periodo de tiempo.', 1),
  (884, 'MEGAQM Ahorro Dólares', 3, 378, 115, 'Renta Fija', 'Argentina', 'Mediano Plazo', NULL, 2, '2019-06-10', 1, '1083', 'Sin datos', 2),
  (629, 'MEGAQM Balanceado', 7, 378, 387, 'Renta Mixta', 'Argentina', 'Largo Plazo', NULL, 1, '2015-08-26', 1, '769', NULL, 0),
  (537, 'MEGAQM Cobertura', 3, 378, 115, 'Renta Fija', 'Argentina', 'Mediano Plazo', NULL, 1, '2017-09-05', 1, '676', 'Obtener cobertura ante la variación del tipo de cambio oficial. El fondo invierte al menos 75% en activos de renta fija con cláusula de ajuste sobre el tipo de cambio oficial como obligaciones negociables; valores de corto plazo; bonos; fideicomisos, principalmente agropecuarios; y/o activos denominados en dólares.', 1),
  (1527, 'MEGAQM Cobertura FCIA Pymes', 6, 378, 387, 'Renta Mixta', 'Argentina', 'Largo Plazo', NULL, 1, '2024-07-23', 1, '1538', 'Pymes.', 1),
