  (1473, 'MEGAQM Estrategia 3', 5, 378, 115, 'Renta Mixta', 'Argentina', 'Mediano Plazo', NULL, 1, '2024-01-16', 1, '1241', 'Sin datos', 1),
  (607, 'MEGAQM Estrategia 4', 3, 378, 387, 'Renta Fija', 'Argentina', 'Corto Plazo', NULL, 1, '2015-03-06', 1, '754', 'El objetivo primario de la administración del FONDO es preservar el valor del patrimonio del FONDO, y en ese marco, obtener ingresos corrientes y ganancias de capital por la compra y venta de ACTIVOS AUTORIZADOS.', 1),
  (602, 'MEGAQM Estrategia 5', 11, 378, 387, 'Renta Fija', 'Argentina', 'Corto Plazo', NULL, 1, '2015-02-20', 1, '756', NULL, 1),
  (635, 'MEGAQM Estrategia 6', 3, 378, 387, 'Renta Fija', 'Argentina', 'Corto Plazo', NULL, 1, '2015-08-31', 1, '770', 'Obtener un rendimiento similar a las colocaciones de Letras del Banco Central de 90 días y disponibilidad de fondos en 24 horas.', 1),
  (376, 'MEGAQM Estrategia 7', 3, 378, 387, 'Renta Fija', 'Argentina', 'Largo Plazo', NULL, 1, '2017-09-05', 1, '514', 'Su administración dinámica intenta capturar las mejores oportunidades del mercado. Permite invertir en una cartera con instrumentos de renta fija argentina.', 1),
  (573, 'MEGAQM Estrategia 8', 5, 378, 115, 'Renta Mixta', 'Argentina', 'Mediano Plazo', NULL, 1, '2017-09-05', 1, '726', 'El fondo tiene como objetivo lograr una rentabilidad ajustada por riesgo, superior a un conjunto de instrumentos de renta fija de corto/mediano plazo mediante una adecuada diversificación de sus activos. El horizonte de inversión del fondo es de corto/mediano plazo.', 1),
  (753, 'MEGAQM Estrategia 9', 3, 378, 115, 'Renta Fija', 'Argentina', 'Mediano Plazo', NULL, 1, '2017-07-03', 1, '964', 'El fondo invertirá en una cartera de activos de renta fija de baja volatilidad, combinando riesgo público y privado, con el objetivo de obtener una rentabilidad por encima de la tasa BADLAR proporcionando liquidez y preservación de capital a los inversores. Podrá invertir en instrumentos del BCRA, títulos públicos nacionales y provinciales, obligaciones negociables de empresas privadas y fideicomisos financieros. Mantendrá un portafolio diversificado con un manejo prudente del riesgo.', 1),
  (628, 'MEGAQM FCI Abierto Financiamiento de Infraestructura', 8, 378, 387, 'Renta Mixta', 'Argentina', 'Largo Plazo', NULL, 1, '2017-09-05', 1, '768', 'El objetivo del fondo es maximizar el rendimiento, para colocaciones mayores a 6 meses, en una cartera diversificada de instrumentos financieros y valores negociables de renta variable y fija destinados al financiamiento de Infraestructura.', 2),
  (1497, 'MEGAQM Gestión Balanceada Dólares', 5, 378, 115, 'Renta Mixta', 'Argentina', 'Flexible', NULL, 2, '2024-04-25', 1, '1080', 'Renta Mixta.', 2),
  (1655, 'MEGAQM Gestión Dólares 2', 3, 378, 115, 'Renta Fija', 'Argentina', 'Corto Plazo', NULL, 2, '2025-05-20', 1, '1651', 'Sin datos', 1),
