  (764, 'MEGAQM Liquidez Dólar', 4, 378, 115, 'Plazo Fijo', 'Argentina', 'Corto Plazo', NULL, 2, '2017-08-03', 1, '895', 'Money Market Dólar.', 0),
  (527, 'MEGAQM Performance II', 3, 378, 115, 'Renta Fija', 'Argentina', 'Corto Plazo', NULL, 1, '2012-05-10', 1, '669', 'Invierte como mínimo un 80% del portafolio en Letras denominadas en pesos emitidas por el Banco Central de la República Argentina. De esta manera busca brindar altos rendimientos liquidez y preservación de capital en el corto plazo.', 1),
  (593, 'MEGAQM Pesos', 4, 378, 387, 'Plazo Fijo', 'Argentina', 'Corto Plazo', NULL, 1, '2014-08-07', 1, '737', 'Remunerar la liquidez de corto plazo con mínima exposición al riesgo.', 0),
  (768, 'MEGAQM Provincial', 3, 378, 387, 'Renta Fija', 'Argentina', 'Mediano Plazo', NULL, 1, '2017-09-06', 1, '951', 'Invertir en una cartera diversificada en instrumentos de deuda provincial, municipal y corporativa garantizada por el sector público acorde a un riguroso análisis de los riesgos de créditos asociados a la situación fiscal de cada provincia.', 1),
  (1585, 'MEGAQM Renta Dólares', 3, 378, 115, 'Renta Fija', 'Argentina', 'Corto Plazo', NULL, 2, '2024-11-05', 1, '1081', 'Sin datos', 1),
  (788, 'MEGAQM Renta Fija LATAM', 3, 378, 115, 'Renta Fija', 'Latinoamerica', 'Mediano Plazo', NULL, 2, '2017-11-07', 1, '906', 'Obtener rendimientos provenientes de renta y apreciación de capital a través de un portafolio diversificado de instrumentos corporativos latinoamericanos de renta fija denominados en dólares.', 2),
  (600, 'MEGAQM Renta Mixta', 5, 378, 115, 'Renta Mixta', 'Argentina', 'Mediano Plazo', NULL, 1, '2017-09-05', 1, '746', 'Tiene como objetivo obtener una rentabilidad por encima de la tasa Badlar, brindando liquidez y preservando el capital en el corto plazo. El Fondo invierte en activos de renta fija, combinando riesgo público y privado y con una estrategia de baja volatilidad y alta liquidez.', 1),
  (746, 'MEGAQM Retorno Absoluto', 7, 378, 387, 'Renta Mixta', 'Argentina', 'Mediano Plazo', NULL, 1, '2017-09-05', 1, '923', 'Obtener un rendimiento similar a la inflación.', 1),
  (588, 'MEGAQM Retorno Total', 7, 378, 115, 'Renta Mixta', 'Argentina', 'Largo Plazo', NULL, 1, '2017-09-05', 1, '728', 'Obtener retornos provenientes de la renta y apreciación de capital de un portafolio diversificado de instrumentos de Renta Fija Argentinos denominados en pesos y dólares. El fondo presenta un horizonte de inversión de mediano y largo plazo con una permanente gestión activa del portafolio.', 1),
