  (266, 'Optimum Dynamic Balanced Fund', 3, 16, 70, 'Renta Fija', 'Argentina', 'Flexible', NULL, 1, '1998-10-15', 1, '305', NULL, 1),
  (229, 'Optimum FAE (Fondo de Aplicaciones Especiales)', 3, 16, 70, 'Renta Fija', 'Argentina', 'Flexible', NULL, 1, '1998-04-30', 1, '276', 'Conformar una cartera de inversión de renta fija argentina con activos locales denominados en USD, con el objetivo de obtener cobertura en USD y/o diversificar activos en pesos.', 1),
  (458, 'Optimum Global Balanced', 5, 49, 96, 'Renta Mixta', 'Argentina', 'Mediano Plazo', NULL, 1, '2009-08-10', 1, '594', 'Conformar una cartera de riesgo balanceado destinado a inversores institucionales que desean una apreciación de su capital mediante una estrategia de Total Return invirtiendo en activos líquidos de renta fija (mayoritariamente soberana) y acciones.', 1),
  (348, 'Optimum Global Investment Grade', 5, 16, 70, 'Renta Mixta', 'Global', 'Largo Plazo', NULL, 1, '2004-05-24', 1, '468', 'Conformar una cartera de activos de renta fija y variable de alta calificación crediticia internacional para lograr una rentabilidad similar a la del índice de referencia.', 1),
  (659, 'Optimum Global Opportunity', 3, 16, 70, 'Renta Fija', 'Argentina', 'Corto Plazo', NULL, 1, '2016-04-22', 1, '788', 'Busca replicar un retorno similar a la tasa BADLAR de bancos privados con una baja volatilidad diaria del valor de cuotaparte. A tal fin, el fondo invierte principalmente en instrumentos locales de renta fija de corto plazo emitidos tanto de emisores públicos como de empresas privadas.', 1),
  (399, 'Optimum Global Renta Mixta', 5, 16, 70, 'Renta Mixta', 'Global', 'Largo Plazo', NULL, 1, '2006-07-19', 1, '491', 'Revalorizar sus activos a mediano plazo invirtiendo principalmente en CEDEARs de acciones del DJ, valores representativos de deuda pública y privada de emisores domiciliados en la República de Chile denominados en USD y fondos mutuos.', 1),
  (1288, 'Optimum Liquidity', 4, 16, 115, 'Plazo Fijo', 'Argentina', 'Corto Plazo', NULL, 1, '2021-11-18', 1, '1157', 'Sin datos', 0),
